message.content:
@startuml
title Get Park Reviews Activity

package "Front End" {
  actor Client
}

package "Back End" {
  rectangle "Website Park Page" as WP
  rectangle "GetParkReviewsActivity" as GPA
  rectangle "Reviews" as REV
}

Client --> WP : Visit park page
WP --> GPA : Send get reviews request
GPA --> REV : Get reviews
REV --> GPA : Reviews item
GPA --> WP : ReviewsModel
WP --> Client : Present reviews

@enduml
